import React from 'react';
import './Header.css';

function Header() {
  return (
    <header className="header">
      <div className="header-content">
        <h1 className="header-title">📚 Bookservice</h1>
        <p className="header-subtitle">Manage your book collection</p>
      </div>
    </header>
  );
}

export default Header;
